#include <stdio.h>
#include <stdlib.h> // For abs, though not strictly needed as an if-else handles it.

int main() {
    int start, end;
    int sum = 0;

    // Read start and end values from stdin
    if (scanf("%d %d", &start, &end) != 2) {
        fprintf(stderr, "Failed to read two integers.\n");
        return 1; // Indicate an error
    }

    // Determine the actual lower and upper bounds for the loop
    int lower_bound;
    int upper_bound;

    if (start < end) {
        lower_bound = start;
        upper_bound = end;
    } else {
        lower_bound = end;
        upper_bound = start;
    }

    // Loop through the determined range
    for (int i = lower_bound; i <= upper_bound; i++) {
        // Check if the current number is odd
        if (i % 2 != 0) {
            sum += i; // Add odd numbers to the sum
        }
    }

    // Print the final sum
    printf("%d\n", sum);

    return 0;
}
